var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……그래서 성탄제를 열고 싶다는 말씀인가요?","JPN":"……それで、聖誕祭の行事を行いたいということですか？","ENG":"...So, you wish to host a Christmas party?","TWN":"……所以你是說想要舉辦聖誕節活動嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 루체 자매님.","JPN":"はい、シスター・ルーチェ。","ENG":"Yes, Sister Luce.","TWN":"是的，露契姊妹。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"작년 성탄절은 성무 때문에 아쉽게도 그냥 넘어갔거든요.","JPN":"昨年の聖誕祭は残念ながら、聖務でお祝いできませんでしたので。","ENG":"We couldn't celebrate it last year due to the sacred mission.","TWN":"去年的聖誕節因為聖務的關係，遺憾地就這樣過去了。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"올해는 그간 신세 졌던 분들을 초대해서 다 함께 성탄절을 보내는 게 어떨까 해서요.","JPN":"今年は今までお世話になった方々を招待して、一緒に聖誕祭を過ごすのはどうでしょうか？","ENG":"But this year, I was thinking of inviting everyone we're thankful for and spending Christmas altogether.","TWN":"今年我想邀請那些一直以來幫助過我們的人，一起過聖誕節。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성탄절이라면 시스터 루퍼가 때마침 사제 심사를 마치고 돌아오는 날이로군요.","JPN":"聖誕祭ならシスター・ルーパーがちょうど司祭審査を終えて帰ってくる日ですね。","ENG":"Also, it just so happens that Christmas is when Sister Looper returns from her priest evaluation.","TWN":"聖誕節的話，也正好是洛珀姊妹完成考核歸來之日呢。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……아주 우연하게도 말이죠.","JPN":"……偶然ながら。","ENG":"...How coincidental.","TWN":"……那真是不巧。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아하하… 그, 그랬나요?","JPN":"あはは……そ、そうでしたか？","ENG":"Ah hah hah... I-is it?","TWN":"啊哈哈……是、是這樣嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그, 그렇지! 그럼, 성탄제에서 루퍼 자매님의 서품 축하를 겸하면 어떨까요?","JPN":"そ、そう！　じゃあ、聖誕祭でシスター・シンディの叙階も一緒に祝うのはどうですか？","ENG":"R-right! So, how about we celebrate Sister Looper's ordination on Christmas too?","TWN":"那、那就這樣吧！那麼，在聖誕節上順便慶祝洛珀姊妹的授職儀式怎麼樣？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"글쎄요, 이상한 대목이네요.","JPN":"さあ、それはどうでしょうか。","ENG":"Well, that seems a bit strange.","TWN":"這個嘛，有些古怪。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 루퍼가 반드시 심사에 통과한다는 보장이 없을 텐데요?","JPN":"シスター・ルーパーが必ずしも審査で合格するという保証はないはずです。","ENG":"There is no guarantee that Sister Looper will pass.","TWN":"洛珀不一定能通過考核吧？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"우, 우으… 그건, 그렇지만…….","JPN":"う、うう……それは、そうですけど……","ENG":"U-um... B-but still–","TWN":"唔、唔呃……那、那是，可是……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"후우, 역시 루체 자매님은 못 속이겠어요.","JPN":"ふう、やはりシスター・ルーチェは騙せません。","ENG":"*Sigh* I guess there's no fooling Sister Luce.","TWN":"呼，果然是無法欺騙露契姊妹啊。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사실은 루퍼 자매님에게 특별한 추억을 만들어 주고 싶거든요.","JPN":"実はシスター・シンディに特別な思い出を作ってあげたいのです。","ENG":"In truth, I wanted to create a special memory for Sister Looper.","TWN":"其實是想給洛珀姊妹留下特別的回憶。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"추억이라고요?","JPN":"思い出ですか？","ENG":"A special memory?","TWN":"回憶嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 왜냐하면 루퍼 자매님은 한 번도 제대로 된 성탄절을 맞이한 적이 없을 테니까요.","JPN":"はい。だって、シスター・シンディは一度もちゃんとした聖誕祭を迎えたことがないでしょうから。","ENG":"Yes. Because she has never properly celebrated Christmas before.","TWN":"是的，因為洛珀姊妹從來沒有過一個真正的聖誕節。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……성무 수행을 위해, CSE 레벨 3 침식 지대에 도착했을 때, 자매님은 혼자였어요.","JPN":"……聖務遂行のためにCSEレベル3の侵食地帯に着いた時、シスター・シンディは1人だったんです。","ENG":"...When I arrived at the CSE Level 3 Corrupted Area for my sacred mission, she was all alone.","TWN":"……為了執行聖務，當到達CSE等級3的侵蝕地帶時，她也一直是一個人。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사교도의 지하실에서 홀린 듯, 홀로 공포 영화를 보고 있었죠.","JPN":"邪教徒の地下室でとり憑かれたように、1人でホラー映画を見ていました。","ENG":"And I saw her watching a horror movie by herself in the cultist's basement as if she was possessed.","TWN":"在邪教徒的地下室裡，像著了魔一樣，獨自看恐怖電影。"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"널브러진 침식체 사체들 한 가운데서 피투성이가 된 채로…….","JPN":"累々と横たわる侵食体の屍の真ん中で血まみれになったまま……","ENG":"She was covered in blood, surrounded by scattered C.O. corpses...","TWN":"在散落著侵蝕體屍體中間，渾身是血……"},"stage":{"bg":"ROOM_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님을 감금했던 사교도들은 보육원으로 위장하여 인권 유린을 저질러왔다고 해요.","JPN":"シスター・シンディを監禁した邪教徒たちは、養護施設と偽装して人権を蹂躙してきたそうです。","ENG":"The cult that imprisoned her committed human rights violations under the guise of an orphanage.","TWN":"據說那些邪教徒，綁架她後，偽裝成孤兒院的工作人員虐待她。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"성무 보고서에는 CSE에 의한 정신 착란이 있었다고 쓰여있었지만.","JPN":"聖務報告書には、CSEによる精神錯乱だと書かれていたんですが。","ENG":"The sacred mission report stated that she had delirium due to CSE, but...","TWN":"聖務報告中寫到，是由CSE引發的精神錯亂。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"정작, 현장에서 구조된 루퍼 자매님의 정신 감정 결과는 이상이 없다고 밝혀졌죠.","JPN":"現場から救助されたシスター・シンディの精神鑑定結果は異常なしということがわかったのです。","ENG":"When Sister Looper had her mental health examined after being rescued, the results showed no abnormalities.","TWN":"事實上，精神鑒定結果顯示，現場獲救的洛珀姊妹精神沒有異常。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아시다시피, 사교도들에 의해 자행된 인권 유린이 꼭 CSE 탓일 리는 없습니다.","JPN":"ご存じでしょうが、邪教徒たちによって行われた人権蹂躙が必ずしもCSEのせいだとは限りません。","ENG":"As you know, the human rights violations committed by the cult cannot necessarily be blamed on CSE.","TWN":"如你所知，由邪教徒們實施的虐待不一定都是CSE的錯。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 인간의 무의식적인 감정 변화가 침식 현상에 영향을 준다는 연구 결과도 있죠.","JPN":"むしろ、人間の無意識の感情変化が侵食現象に影響するという研究結果もあります。","ENG":"Rather, there is research that shows that the subconscious emotional change in humans can affect the Counterside Effect.","TWN":"反而有研究結果表明，人類無意識的情感變化會影響侵蝕現象。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};